export interface PracticeQuestion {
  id: string;
  difficulty: "facile" | "moyen" | "difficile";
  question: string;
  answer: string;
  explanation?: string;
}

export type PracticeQuestionsMap = Record<string, PracticeQuestion[]>;

/** Normalize a subject name to a key fragment */
export function normalizeSubject(s: string): string {
  return s
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/['\u2019]/g, "_")
    .replace(/[\s\-]+/g, "_")
    .replace(/[^a-z0-9_]/g, "");
}

/** Build the lookup key from class fields */
export function makePracticeKey(niveauKey: string, sectionKey: string | null, subject: string): string {
  const sub = normalizeSubject(subject);
  return sectionKey ? `${niveauKey}_${sectionKey}_${sub}` : `${niveauKey}_${sub}`;
}

