  "2eme_sciences_mathematiques": [
    { id: "2sc_math_001", difficulty: "facile", question: "Calcule la dérivée de f(x) = x² + 3x − 5", answer: "f′(x) = 2x + 3", explanation: "Dérivation terme à terme" },
    { id: "2sc_math_002", difficulty: "facile", question: "Résous : x² − 4 = 0", answer: "x = 2 ou x = −2", explanation: "x² = 4 → x = ±2" },
    { id: "2sc_math_003", difficulty: "facile", question: "Calcule le discriminant de x² − 5x + 6 = 0", answer: "Δ = 25 − 24 = 1", explanation: "Δ = b² − 4ac = 25−24" },
    { id: "2sc_math_004", difficulty: "moyen", question: "Dresse le tableau de variations de f(x) = x² − 4x + 1", answer: "f′(x) = 2x−4, minimum en x=2, f(2)=−3", explanation: "f′(x)=0 → x=2" },
    { id: "2sc_math_005", difficulty: "moyen", question: "Calcule ∫₀¹ (x²+1) dx", answer: "4/3", explanation: "[x³/3 + x]₀¹ = 1/3+1 = 4/3" },
    { id: "2sc_math_006", difficulty: "moyen", question: "Résous le système : x+y=5 et 2x−y=1", answer: "x=2, y=3", explanation: "Addition : 3x=6 → x=2, y=5−2=3" },
    { id: "2sc_math_007", difficulty: "difficile", question: "Détermine les asymptotes de f(x) = (x²+1)/(x−2)", answer: "AV : x=2, AO : y=x+2", explanation: "Division euclidienne : x²+1 = (x−2)(x+2) + 5" },
    { id: "2sc_math_008", difficulty: "difficile", question: "Étudie la parité de f(x) = x³ − x", answer: "Fonction impaire : f(−x) = −f(x)", explanation: "(−x)³−(−x) = −x³+x = −(x³−x)" },
    { id: "2sc_math_009", difficulty: "difficile", question: "Démontre que l'équation x³ + x − 1 = 0 a une solution dans ]0,1[.", answer: "f(0)=−1<0, f(1)=1>0. Par TVI (f continue), ∃c∈]0,1[ tel que f(c)=0.", explanation: "Théorème des valeurs intermédiaires (Bolzano)" },
  ],

  "2eme_sciences_physique_chimie": [
    { id: "2sc_pc_001", difficulty: "facile", question: "Énonce la loi de Newton (2ème loi).", answer: "ΣF = ma : la somme des forces = masse × accélération.", explanation: "Unités : N = kg·m/s²" },
    { id: "2sc_pc_002", difficulty: "facile", question: "Qu'est-ce que l'énergie cinétique ?", answer: "Ec = (1/2)mv² — énergie due au mouvement d'un objet de masse m à vitesse v.", explanation: "Unité : Joule (J) = kg·m²/s²" },
    { id: "2sc_pc_003", difficulty: "facile", question: "Définis le pH et donne son expression pour un acide fort.", answer: "pH = −log[H₃O⁺]. Pour un acide fort de concentration C : pH = −log(C).", explanation: "pH < 7 : acide, pH = 7 : neutre, pH > 7 : basique" },
    { id: "2sc_pc_004", difficulty: "moyen", question: "Un corps de masse 2 kg tombe de 10 m. Quelle est sa vitesse à l'impact ?", answer: "v = √(2gh) = √(2×10×10) = √200 ≈ 14.1 m/s", explanation: "Conservation de l'énergie mécanique : mgh = (1/2)mv²" },
    { id: "2sc_pc_005", difficulty: "moyen", question: "Calcule le pH d'une solution de NaOH 0.001 M.", answer: "pOH = 3, pH = 14−3 = 11", explanation: "NaOH est une base forte : [OH⁻] = 0.001 M" },
    { id: "2sc_pc_006", difficulty: "moyen", question: "Donne la configuration électronique du Fer (Z=26).", answer: "1s²2s²2p⁶3s²3p⁶3d⁶4s²", explanation: "Règle de Klechkowski : remplissage par énergie croissante" },
    { id: "2sc_pc_007", difficulty: "difficile", question: "Calcule l'énergie libérée lors de la fusion de 1 kg de glace puis chauffage à 100°C.", answer: "Q = mLf + mcΔT = 1×334 000 + 1×4180×100 = 752 000 J", explanation: "Chaleur de fusion + chaleur sensible" },
    { id: "2sc_pc_008", difficulty: "difficile", question: "Décris et calcule la chute libre d'un objet lâché depuis 45 m.", answer: "t = √(2h/g) = √(90/10) = 3 s, v = gt = 30 m/s", explanation: "y = (1/2)gt², v = gt (g ≈ 10 m/s²)" },
    { id: "2sc_pc_009", difficulty: "difficile", question: "Titrage de 20 mL de HCl par NaOH 0.1 M : 15 mL versés à l'équivalence. Trouve la concentration de HCl.", answer: "C_HCl × 20 = C_NaOH × 15 → C_HCl = 0.075 M", explanation: "À l'équivalence : n(HCl) = n(NaOH)" },
  ],

  // ═══════════════════════════════════════════════════════════
  // 1ÈRE SECONDAIRE
