  "1ere_secondaire_mathematiques": [
    { id: "1s_math_001", difficulty: "facile", question: "Développe et simplifie : (x+3)(x−2)", answer: "x² + x − 6", explanation: "FOIL : x²−2x+3x−6 = x²+x−6" },
    { id: "1s_math_002", difficulty: "facile", question: "Résous : 2x + 5 = 13", answer: "x = 4", explanation: "2x = 8 → x = 4" },
    { id: "1s_math_003", difficulty: "facile", question: "Calcule la pente de la droite passant par A(1,2) et B(3,6).", answer: "m = (6−2)/(3−1) = 2", explanation: "m = (y₂−y₁)/(x₂−x₁)" },
    { id: "1s_math_004", difficulty: "moyen", question: "Résous : x² − 6x + 8 = 0", answer: "x = 2 ou x = 4", explanation: "Δ = 36−32 = 4, x = (6±2)/2" },
    { id: "1s_math_005", difficulty: "moyen", question: "Calcule l'aire d'un triangle de base 8 cm et hauteur 5 cm.", answer: "A = (8×5)/2 = 20 cm²", explanation: "Aire du triangle = (base × hauteur) / 2" },
    { id: "1s_math_006", difficulty: "moyen", question: "Factorise : x² − 9", answer: "(x−3)(x+3)", explanation: "Identité remarquable : a²−b² = (a−b)(a+b)" },
    { id: "1s_math_007", difficulty: "difficile", question: "Résous le système : 3x + 2y = 12 et x − y = 1", answer: "x = 2, y = 1... attendez : 3(2)+2(1)=8≠12. Correction : x=14/5, y=9/5", explanation: "Méthode de substitution : x = y+1 → 3(y+1)+2y = 12 → 5y = 9 → y=9/5" },
    { id: "1s_math_008", difficulty: "difficile", question: "Calcule sin(60°) et cos(30°) sans calculatrice.", answer: "sin(60°) = √3/2 ≈ 0.866, cos(30°) = √3/2", explanation: "Triangle équilatéral coupé en deux : hyp=2, côtés 1 et √3" },
    { id: "1s_math_009", difficulty: "difficile", question: "Démontre le théorème de Pythagore.", answer: "Dans un carré de côté (a+b) : aire totale = (a+b)² = 4×(1/2)ab + c² → a²+b²=c².", explanation: "Preuve géométrique classique" },
  ],

  "1ere_secondaire_physique_chimie": [
    { id: "1s_pc_001", difficulty: "facile", question: "Quelle est la différence entre masse et poids ?", answer: "Masse (kg) : quantité de matière, invariable. Poids (N) : force gravitationnelle P = mg.", explanation: "Sur la Lune : même masse, poids 6 fois plus faible" },
    { id: "1s_pc_002", difficulty: "facile", question: "Définis la densité d'un corps.", answer: "d = masse volumique du corps / masse volumique de l'eau = ρ/ρ_eau", explanation: "d > 1 → coule dans l'eau, d < 1 → flotte" },
    { id: "1s_pc_003", difficulty: "facile", question: "Qu'est-ce qu'un atome neutre ?", answer: "Atome dont le nombre de protons = nombre d'électrons (charge nulle).", explanation: "Nombre de protons = numéro atomique Z" },
    { id: "1s_pc_004", difficulty: "moyen", question: "Un ressort de raideur k=200 N/m est allongé de 5 cm. Calcule la force.", answer: "F = k×x = 200×0.05 = 10 N", explanation: "Loi de Hooke : F = kx (en Newton)" },
    { id: "1s_pc_005", difficulty: "moyen", question: "Calcule la masse molaire de H₂O.", answer: "M = 2×1 + 16 = 18 g/mol", explanation: "H : 1 g/mol, O : 16 g/mol" },
    { id: "1s_pc_006", difficulty: "moyen", question: "Qu'est-ce qu'une liaison covalente ?", answer: "Liaison entre deux atomes par mise en commun d'une ou plusieurs paires d'électrons.", explanation: "Exemple : H−H, H₂O, CO₂" },
    { id: "1s_pc_007", difficulty: "difficile", question: "Calcule le nombre de molécules dans 9 g d'eau.", answer: "n = 9/18 = 0.5 mol → N = 0.5 × 6.02×10²³ ≈ 3.01×10²³ molécules", explanation: "N_A = 6.02×10²³ mol⁻¹ (nombre d'Avogadro)" },
    { id: "1s_pc_008", difficulty: "difficile", question: "Décris le modèle de Bohr de l'atome d'hydrogène.", answer: "Électron sur des orbites circulaires quantifiées. Énergie En = −13.6/n² eV.", explanation: "Sauts d'orbites → émission/absorption de photons" },
    { id: "1s_pc_009", difficulty: "difficile", question: "Calcule la vitesse du son dans l'air : f=440 Hz, λ=0.773 m.", answer: "v = f×λ = 440×0.773 ≈ 340 m/s", explanation: "Relation onde : v = fλ" },
  ],

  // ═══════════════════════════════════════════════════════════
  // 9ÈME ANNÉE DE BASE
