  "9eme_mathematiques": [
    { id: "9m_math_001", difficulty: "facile", question: "Calcule : 3/4 + 1/6", answer: "11/12", explanation: "3/4 = 9/12, 1/6 = 2/12 → 11/12" },
    { id: "9m_math_002", difficulty: "facile", question: "Quel est 15% de 200 ?", answer: "30", explanation: "200 × 0.15 = 30" },
    { id: "9m_math_003", difficulty: "facile", question: "Simplifie : 2x + 3x − x", answer: "4x", explanation: "Regrouper les termes semblables" },
    { id: "9m_math_004", difficulty: "moyen", question: "Résous : 2x − 5 = 11", answer: "x = 8", explanation: "2x = 16 → x = 8" },
    { id: "9m_math_005", difficulty: "moyen", question: "Une voiture roule à 90 km/h pendant 2h30. Quelle distance parcourt-elle ?", answer: "225 km", explanation: "d = v×t = 90 × 2.5 = 225 km" },
    { id: "9m_math_006", difficulty: "moyen", question: "Calcule l'aire d'un cercle de rayon 7 cm. (π ≈ 3.14)", answer: "A = π×r² ≈ 3.14×49 ≈ 153.86 cm²", explanation: "A = πr²" },
    { id: "9m_math_007", difficulty: "difficile", question: "Résous : 3(2x−1) = 2(x+5) + 7", answer: "6x−3 = 2x+17 → 4x = 20 → x = 5", explanation: "Développer puis isoler x" },
    { id: "9m_math_008", difficulty: "difficile", question: "Un robinet remplit un réservoir en 6h, un autre en 4h. Combien de temps si ouverts ensemble ?", answer: "2h24min (= 12/5 h)", explanation: "Débit total : 1/6 + 1/4 = 5/12 par heure → t = 12/5 h" },
    { id: "9m_math_009", difficulty: "difficile", question: "Démontre que la somme des angles d'un triangle est égale à 180°.", answer: "Tracer une parallèle à la base par le sommet : angles alternes-internes montrent que les 3 angles forment 180°.", explanation: "Preuve par droites parallèles" },
  ],

  "9eme_francais": [
    { id: "9m_fr_001", difficulty: "facile", question: "Qu'est-ce qu'un nom propre ? Donne 3 exemples.", answer: "Nom désignant une personne, un lieu ou une organisation spécifique. Ex : Paris, Mohamed, Étude+.", explanation: "S'écrit avec une majuscule" },
    { id: "9m_fr_002", difficulty: "facile", question: "Conjugue 'finir' au présent de l'indicatif.", answer: "je finis, tu finis, il/elle finit, nous finissons, vous finissez, ils/elles finissent", explanation: "Verbe du 2ème groupe : base + is/is/it/issons/issez/issent" },
    { id: "9m_fr_003", difficulty: "facile", question: "Qu'est-ce qu'un adjectif qualificatif ?", answer: "Mot qui qualifie un nom en indiquant une qualité ou un état. Ex : 'un livre intéressant'.", explanation: "S'accorde en genre et en nombre avec le nom" },
    { id: "9m_fr_004", difficulty: "moyen", question: "Identifie le temps et justifie : 'Il avait terminé son devoir avant d'aller jouer.'", answer: "Plus-que-parfait (avait terminé) : action accomplie avant une autre action passée.", explanation: "Auxiliaire à l'imparfait + participe passé" },
    { id: "9m_fr_005", difficulty: "moyen", question: "Transforme à la voix passive : 'Le professeur corrige les copies.'", answer: "Les copies sont corrigées par le professeur.", explanation: "Sujet actif → complément d'agent, COD → sujet, verbe accordé" },
    { id: "9m_fr_006", difficulty: "moyen", question: "Explique la différence entre une comparaison et une métaphore.", answer: "Comparaison : outil explicite (comme, tel). Métaphore : identification directe sans outil.", explanation: "'brave comme un lion' vs 'il est un lion'" },
    { id: "9m_fr_007", difficulty: "difficile", question: "Rédige un paragraphe argumentatif sur : 'La lecture est utile.'", answer: "Thèse + argument + exemple + conclusion. Ex : 'La lecture enrichit le vocabulaire (argument). Des études montrent que les lecteurs réguliers réussissent mieux à l'école (exemple).'", explanation: "Structure : thèse → argument → exemple → clôture" },
    { id: "9m_fr_008", difficulty: "difficile", question: "Analyse grammaticalement : 'Les élèves studieux réussissent toujours leurs examens.'", answer: "Les (article défini pluriel), élèves (nom sujet pluriel), studieux (adj. épithète), réussissent (verbe), toujours (adv.), leurs examens (COD).", explanation: "Identifier la fonction de chaque groupe" },
    { id: "9m_fr_009", difficulty: "difficile", question: "Qu'est-ce que le champ lexical ? Donne un exemple avec 'mer'.", answer: "Ensemble de mots en rapport avec un même thème. Champ lexical de 'mer' : vague, plage, sable, marin, horizon, sel.", explanation: "Outil d'analyse littéraire pour identifier les thèmes d'un texte" },
  ],

  "9eme_sciences_naturelles": [
    { id: "9m_sn_001", difficulty: "facile", question: "Quels sont les 5 grands groupes d'êtres vivants ?", answer: "Bactéries, Protistes, Champignons, Végétaux, Animaux.", explanation: "Classification du vivant (règnes)" },
    { id: "9m_sn_002", difficulty: "facile", question: "Qu'est-ce que la cellule ?", answer: "Unité structurale et fonctionnelle de base de tous les êtres vivants.", explanation: "Théorie cellulaire : Schleiden et Schwann (1839)" },
    { id: "9m_sn_003", difficulty: "facile", question: "Définis la photosynthèse simplement.", answer: "Processus par lequel les plantes fabriquent leur nourriture grâce à la lumière, l'eau et le CO₂.", explanation: "CO₂ + H₂O + lumière → glucose + O₂" },
    { id: "9m_sn_004", difficulty: "moyen", question: "Quelle est la différence entre cellule animale et cellule végétale ?", answer: "Végétale : paroi cellulaire en cellulose, chloroplastes, grande vacuole centrale. Animale : aucun de ces éléments.", explanation: "Les deux ont : noyau, mitochondries, membrane plasmique" },
    { id: "9m_sn_005", difficulty: "moyen", question: "Explique la digestion chimique dans l'estomac.", answer: "L'acide chlorhydrique (HCl) et la pepsine dégradent les protéines en peptides.", explanation: "pH très acide (≈2) de l'estomac active les enzymes" },
    { id: "9m_sn_006", difficulty: "moyen", question: "Qu'est-ce que la chaîne alimentaire ? Donne un exemple.", answer: "Suite d'organismes où chacun mange le précédent. Ex : herbe → lapin → renard → décomposeurs.", explanation: "Transfert d'énergie entre niveaux trophiques" },
    { id: "9m_sn_007", difficulty: "difficile", question: "Explique le mécanisme de la respiration cellulaire.", answer: "Glucose + O₂ → CO₂ + H₂O + ATP. Se déroule dans les mitochondries. Libère l'énergie stockée dans le glucose.", explanation: "C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + 36 ATP" },
    { id: "9m_sn_008", difficulty: "difficile", question: "Décris le cycle de l'eau dans la nature.", answer: "Évaporation → condensation → précipitation → infiltration/ruissellement → retour mer/lacs → évaporation.", explanation: "Énergie solaire et gravité sont les moteurs du cycle" },
    { id: "9m_sn_009", difficulty: "difficile", question: "Qu'est-ce que l'immunité et comment fonctionne-t-elle ?", answer: "Capacité de l'organisme à se défendre contre les agents pathogènes. Immunité innée (immédiate) + adaptative (anticorps spécifiques).", explanation: "Lymphocytes B → anticorps. Lymphocytes T → destruction directe" },
  ],

  // ═══════════════════════════════════════════════════════════
