  "8eme_mathematiques": [
    { id: "8m_math_001", difficulty: "facile", question: "Calcule : 2/3 + 1/4", answer: "11/12", explanation: "PPCM(3,4) = 12 : 8/12 + 3/12 = 11/12" },
    { id: "8m_math_002", difficulty: "facile", question: "Développe : (x+2)²", answer: "x² + 4x + 4", explanation: "(a+b)² = a²+2ab+b²" },
    { id: "8m_math_003", difficulty: "facile", question: "Calcule l'aire d'un rectangle 6 cm × 4 cm.", answer: "24 cm²", explanation: "A = longueur × largeur" },
    { id: "8m_math_004", difficulty: "moyen", question: "Résous : 4x + 3 = 2x − 5", answer: "x = −4", explanation: "4x−2x = −5−3 → 2x = −8 → x = −4" },
    { id: "8m_math_005", difficulty: "moyen", question: "Calcule le pourcentage d'augmentation : de 80 à 100.", answer: "25%", explanation: "(100−80)/80 × 100 = 20/80 × 100 = 25%" },
    { id: "8m_math_006", difficulty: "moyen", question: "Factorise : 6x² + 9x", answer: "3x(2x + 3)", explanation: "Facteur commun 3x" },
    { id: "8m_math_007", difficulty: "difficile", question: "Calcule l'hypoténuse d'un triangle rectangle de côtés 5 et 12.", answer: "13", explanation: "Pythagore : c = √(25+144) = √169 = 13" },
    { id: "8m_math_008", difficulty: "difficile", question: "Résous le système : x+y=7 et 2x−y=2", answer: "x=3, y=4", explanation: "Addition : 3x=9 → x=3, y=7−3=4" },
    { id: "8m_math_009", difficulty: "difficile", question: "Calcule le volume d'un cylindre de rayon 3 cm et hauteur 10 cm.", answer: "V = π×r²×h ≈ 282.7 cm³", explanation: "V = πr²h = 3.14×9×10" },
  ],

